702→void ConnectionManagerImpl::maybeDrainDueToPrematureResets() {
   703→  // If the connection has been drained due to premature resets, do not check this again.
   704→  // Without this flag, recursion may occur, as shown in the following stack trace:
   705→  //
   706→  //   maybeDrainDueToPrematureResets()
   707→  //   doConnectionClose()
   708→  //   resetAllStreams()
   709→  //   onResetStream()
   710→  //   doDeferredStreamDestroy()
   711→  //   maybeDrainDueToPrematureResets()
   712→  //   ...
   713→  //
   714→  // The recursion will continue until all streams are destroyed. If there are many streams
   715→  // that may result in a stack overflow. This flag is used to avoid above recursion.
   716→  if (drained_due_to_premature_resets_) {
   717→    return;
   718→  }
   719→
   720→  if (closed_non_internally_destroyed_requests_ == 0) {
   721→    return;
   722→  }
   723→
   724→  const uint64_t limit =
   725→      runtime_.snapshot().getInteger(ConnectionManagerImpl::PrematureResetTotalStreamCountKey, 500);
   726→
   727→  if (closed_non_internally_destroyed_requests_ < limit) {
   728→    // Even though the total number of streams have not reached `limit`, check if the number of bad
   729→    // streams is high enough that even if every subsequent stream is good, the connection
   730→    // would be closed once the limit is reached, and if so close the connection now.
   731→    if (number_premature_stream_resets_ * 2 < limit) {
   732→      return;
   733→    }
   734→  } else {
   735→    if (number_premature_stream_resets_ * 2 < closed_non_internally_destroyed_requests_) {
   736→      return;
   737→    }
   738→  }
   739→
   740→  if (read_callbacks_->connection().state() == Network::Connection::State::Open) {
   741→    stats_.named_.downstream_rq_too_many_premature_resets_.inc();
   742→
   743→    // Mark the the connection has been drained due to too many premature resets.
   744→    drained_due_to_premature_resets_ = true;
   745→
   746→    doConnectionClose(Network::ConnectionCloseType::Abort, absl::nullopt,
   747→                      "too_many_premature_resets");
   748→  }
   749→}
   750→
   751→void ConnectionManagerImpl::onGoAway(GoAwayErrorCode) {
   752→  // Currently we do nothing with remote go away frames. In the future we can decide to no longer
   753→  // push resources if applicable.
   754→}
   755→
   756→void ConnectionManagerImpl::onIdleTimeout() {
   757→  ENVOY_CONN_LOG(debug, "idle timeout", read_callbacks_->connection());
   758→  stats_.named_.downstream_cx_idle_timeout_.inc();
   759→  if (!codec_) {
   760→    // No need to delay close after flushing since an idle timeout has already fired. Attempt to
   761→    // write out buffered data one last time and issue a local close if successful.
   762→    doConnectionClose(Network::ConnectionCloseType::FlushWrite, absl::nullopt,
   763→                      StreamInfo::LocalCloseReasons::get().IdleTimeoutOnConnection);
   764→  } else if (drain_state_ == DrainState::NotDraining) {
   765→    startDrainSequence();
   766→  }
   767→}
   768→
   769→void ConnectionManagerImpl::onConnectionDurationTimeout() {
   770→  ENVOY_CONN_LOG(debug, "max connection duration reached", read_callbacks_->connection());
   771→  stats_.named_.downstream_cx_max_duration_reached_.inc();
   772→  if (!codec_) {
   773→    // Attempt to write out buffered data one last time and issue a local close if successful.
   774→    doConnectionClose(Network::ConnectionCloseType::FlushWrite,
   775→                      StreamInfo::CoreResponseFlag::DurationTimeout,
   776→                      StreamInfo::ResponseCodeDetails::get().DurationTimeout);
   777→  } else if (drain_state_ == DrainState::NotDraining) {
   778→    if (config_->http1SafeMaxConnectionDuration() && codec_->protocol() < Protocol::Http2) {
   779→      ENVOY_CONN_LOG(debug,
   780→                     "HTTP1-safe max connection duration is configured -- skipping drain sequence.",
   781→                     read_callbacks_->connection());
   782→      stats_.named_.downstream_cx_http1_soft_drain_.inc();
   783→      soft_drain_http1_ = true;
   784→    } else {
   785→      startDrainSequence();
   786→    }
   787→  }
   788→}
   789→
   790→void ConnectionManagerImpl::onDrainTimeout() {
   791→  ASSERT(drain_state_ != DrainState::NotDraining);
   792→  codec_->goAway();
   793→  drain_state_ = DrainState::Closing;
   794→  checkForDeferredClose(false);
   795→}
